#include <bits/stdc++.h>
using namespace std;
const int maxn=1e7+5;
string s;
int l,a[maxn];
int main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>s;
	for(int i=0;i<s.size();i++){
		if(s[i]>='0'&&s[i]<='9'){
			a[++l]=(s[i]-'0');
		}
	}
	sort(a+1,a+l+1);
	for(int i=l;i>0;i--){
		cout<<a[i];
	}
	return 0;
}
